class Solution {
public:
    double minTime(int n, int k, int m, vector<int>& time, vector<double>& mul) {
        if (n == 1) return time[0] * mul[0];
        if (k == 1) return -1.0;

        const int full = (1 << n) - 1;
        vector<double> dp(1 << n, 1e18);
        dp[0] = 0.0;

        for (int mask = 0; mask <= full; ++mask) {
            if (dp[mask] > 1e17) continue;
            int stage = (static_cast<int>(dp[mask]) % m + m) % m;

            int rem = full ^ mask;
            for (int sub = rem; sub; sub = (sub - 1) & rem) {
                if (__builtin_popcount(sub) > k) continue;
                int max_t = 0;
                for (int i = 0; i < n; ++i)
                    if (sub & (1 << i)) max_t = max(max_t, time[i]);
                double cross = max_t * mul[stage];
                int new_stage = (stage + static_cast<int>(cross)) % m;
                int new_mask = mask | sub;
                if (new_mask == full) {
                    dp[new_mask] = min(dp[new_mask], dp[mask] + cross);
                    continue;
                }
                for (int r = 0; r < n; ++r) {
                    if (!(new_mask & (1 << r))) continue;
                    double back = time[r] * mul[new_stage];
                    int final_stage = (new_stage + static_cast<int>(back)) % m;
                    dp[new_mask ^ (1 << r)] = min(dp[new_mask ^ (1 << r)], dp[mask] + cross + back);
                }
            }
        }
        return dp[full] > 1e17 ? -1.0 : dp[full];
    }
};
